mapper.select:
SELECT m.id, m.message_id, m.session_id, m.user_id, m.tenant_id, m.user_msg, m.ai_reply, m.status,
       m.trace_id, m.created_by, m.created_at, m.updated_by, m.updated_at, m.deleted
FROM cs_message m
INNER JOIN cs_session s ON s.session_id = m.session_id AND s.deleted = FALSE
WHERE m.deleted = FALSE
  AND m.user_id = #{userId}
  AND m.tenant_id = #{tenantId}
  AND s.user_id = #{userId}
  AND s.tenant_id = #{tenantId}

  AND m.session_id = #{sessionId}

ORDER BY m.created_at ASC, m.id ASC

SELECT id, message_id, session_id, user_id, tenant_id, user_msg, ai_reply, status,
       trace_id, created_by, created_at, updated_by, updated_at, deleted
FROM cs_message
WHERE deleted = FALSE
  AND message_id = #{messageId}
  AND user_id = #{userId}
  AND tenant_id = #{tenantId}
LIMIT 1

mapper.update:
UPDATE cs_message
SET deleted = TRUE,
    updated_at = CURRENT_TIMESTAMP
WHERE deleted = FALSE
  AND message_id = #{messageId}
  AND user_id = #{userId}
  AND tenant_id = #{tenantId}
